frappe.ui.form.on('Sales Invoice', {
    setup: function(frm) {
        // Define your custom scroll and sticky layouts
        const pos_layout_css = `
            /* Container styling constraints */
            #sales-invoice-__details {
                max-height: 83vh !important; 
                overflow: hidden !important;
                position: relative !important;
            }

            /* Make the items child table inner grid body scrollable */
            [data-fieldname="items"] .grid-body {
                max-height: 25vh !important;
                overflow-y: auto !important;
                overflow-x: hidden !important;
            }

            /* Pin the column header row to the top of the scroll container */
            [data-fieldname="items"] .grid-heading-row {
                position: sticky !important;
                top: 0 !important;
                z-index: 3 !important;
                background-color: var(--scrollbar-track-color, #f8f9fa) !important;
                box-shadow: 0 1px 2px rgba(0, 0, 0, 0.1) !important;
            }


        `;

        // Inject the CSS styles into the HTML DOM HEAD element safely
        frappe.dom.set_style(pos_layout_css, 'quick_invoice_scroll_theme');

    },

    onload(frm) {
        setTimeout(() => {
            $('[data-fieldname="naming_series"]').hide();
        }, 100);

        // Only for new documents
        if (frm.is_new()) {
            // Add rows if table is empty
            if (frm.doc.items.length <= 1) {
                for (let i = 0; i < 50; i++) {
                    let row = frm.add_child('items');
                }
            }

            let grid = frm.get_field('items').grid;

        grid.page_length = 1000;
        grid.lazy_load = false;
        grid.refresh();
        }
    },

    refresh(frm) {
        $('[data-fieldname="naming_series"]').hide();
    },
    before_save(frm) {

        // Remove blank rows
        frm.doc.items = frm.doc.items.filter(row => {
            return row.item_code &&
                   row.item_code.trim() !== "";
        });

        frm.refresh_field('items');

        // Validation: minimum 1 item required
        if (frm.doc.items.length === 0) {

                for (let i = 0; i < 50; i++) {
                    let row = frm.add_child('items');
                }
                frm.refresh_field('items');


            frappe.msgprint({
                title: __('Warning'),
                message: __('At least one item is required.'),
                indicator: 'red'
            });



            frappe.validated = false;


        }
    }
});


frappe.ui.form.on('Sales Invoice Item', {
    item_code: function(frm, cdt, cdn) {
        trigger_immediate_totals_recalc(frm);
    },

    qty: function(frm, cdt, cdn) {
        trigger_immediate_totals_recalc(frm);
    },

    free_qty: function(frm, cdt, cdn) {
        // Ensure changes to your custom free_qty field also trigger an immediate recalculation pass
        trigger_immediate_totals_recalc(frm);
    },

    rate: function(frm, cdt, cdn) {
        trigger_immediate_totals_recalc(frm);
    },

    discount_percentage: function(frm, cdt, cdn) {
        trigger_immediate_totals_recalc(frm);
    },

    items_remove: function(frm, cdt, cdn) {
        // Fires automatically when a row is deleted via the 'X' button
        trigger_immediate_totals_recalc(frm);
    }
});

function trigger_immediate_totals_recalc(frm) {
    // 1. Force the internal core accounting module to evaluate current row states
    frm.cscript.calculate_taxes_and_totals();

    // 2. Refresh the native field layout displays on the user's screen view instantly
    frm.refresh_field('net_total');
    frm.refresh_field('total_taxes_and_charges');
    frm.refresh_field('grand_total');
    frm.refresh_field('taxes'); // Refreshes the standard tax distribution table matrix rows
}
